const fs=require("fs"),path=require("path");function replaceInDir(e){fs.readdirSync(e).forEach(i=>{const l=path.join(e,i);if(fs.statSync(l).isFile()&&i.endsWith(".html"))try{let e=fs.readFileSync(l,"utf8");e.includes("Epävirallinen yhteisösovellus")&&(e=e.split("Epävirallinen yhteisösovellus").join("Palvelua ylläpitää Mediazoo.fi"),fs.writeFileSync(l,e,"utf8"),console.log("Updated "+l))}catch(e){console.error("Error reading "+l,e)}})}replaceInDir("."),replaceInDir("./dist");